VALUES
  ('social-worker-moex-05870', 'social-worker', 'social-worker-moex-105-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '分層隨機抽樣是實務上常用的抽樣方法，關於其步驟或陳述，下列何者正確？ 最好符合各類（層）之間個體的同質性要高，各類（層）之內個體的異質性高 獲得之樣本不具代表性，抽樣效率低 母群體中的人口資料， 若各層人數比例差異過大，適合使用加權（weighting）處理 不同類（層）之間不需互斥', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "90e183535e49", "answer_pdf_sha1": "da9b90c792c6", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 4, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05871', 'social-worker', 'social-worker-moex-105-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '若社工人員將個案滿意度問卷中的所有題目進行預試，藉由統計軟體進行「因素分析」計算，歸納出三 個因素，這三個因素的負荷狀況也呼應理論結果，此為何種效度？ 建構效度  效標關聯效度  預測效度  同時效度', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "90e183535e49", "answer_pdf_sha1": "da9b90c792c6", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 5, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05872', 'social-worker', 'social-worker-moex-105-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '關於問卷調查的實施方式，下列敘述何者正確？ 相較於面對面訪談或填寫，郵寄問卷的完成率較高 將問卷放置於網路上，讓網路使用者自行填寫，研究結果的推論容易受到限制 相較於面對面訪談或填寫，電話訪談的問卷題目數量可以更多 相較於面對面訪談或填寫，郵寄問卷的回收速度更快', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "90e183535e49", "answer_pdf_sha1": "da9b90c792c6", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 6, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05873', 'social-worker', 'social-worker-moex-105-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '若研究議題牽涉複雜或敏感領域、想要蒐集深度資料、研究問題可以被解釋或想繼續追問時，較適合選 用下列何種方法蒐集資料？ 內容分析法  歷史研究法  實驗法  面對面訪談', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "90e183535e49", "answer_pdf_sha1": "da9b90c792c6", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 7, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05874', 'social-worker', 'social-worker-moex-105-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '在問卷的施測中，用同一種測量，對同一群受試者前後測驗兩次，再依據這兩次測驗的分數，計算其相 關係數，此種測驗的可信度稱為： 再測信度  折半信度  分數信度  複本信度', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "90e183535e49", "answer_pdf_sha1": "da9b90c792c6", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 8, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05875', 'social-worker', 'social-worker-moex-105-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '研究者想知道某些特定對象的酗酒情況，若到該特定對象居住社區的垃圾桶計算空酒瓶數量，將此作為 補充性佐證，此種資料蒐集方式稱為： 非干擾測量（非反應式研究）  問卷調查 實驗設計    深度訪談', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "90e183535e49", "answer_pdf_sha1": "da9b90c792c6", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 9, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05876', 'social-worker', 'social-worker-moex-105-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '關於行動研究的敘述，下列何者正確？ 研究的外在效度較不受限 一種研究取向，且限制只能使用單一種研究方法 不強調實務作者參與 結合研究的過程和步驟，找出解決或改變實務工作困境的策略', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "90e183535e49", "answer_pdf_sha1": "da9b90c792c6", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 10, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05877', 'social-worker', 'social-worker-moex-105-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '實務上，對年長者服務的滿意度調查，結果常為「非常態趨勢」，進而影響後續統計檢定方法的使用。 假設今日的滿意度調查為比例尺度資料，資料為左偏趨勢（負偏態），其平均數、中位數和眾數三個數 值的大小關係為何？ 平均數等於中位數，中位數等於眾數  平均數小於中位數，中位數小於眾數 眾數小於中位數，中位數小於平均數  中位數小於眾數，眾數小於平均數', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "90e183535e49", "answer_pdf_sha1": "da9b90c792c6", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 11, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05878', 'social-worker', 'social-worker-moex-105-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '下列何者不是資料分散（變異）趨勢的指標？ 平均數  變異數  標準差  全距', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "90e183535e49", "answer_pdf_sha1": "da9b90c792c6", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 12, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05879', 'social-worker', 'social-worker-moex-105-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '某機構社工人員為了解處遇成效，由全體個案中隨機抽取30名個案，在處遇施行之前先透過量表進行前 測，同一群人，在處遇施行之後透過相同量表再施行後測。假設已經知道兩次測量結果皆為常態分布， 且資料為比例尺度，若要進行假設檢定兩次測量結果是否有顯著差異，下列何種統計檢定方法較適合？ Z檢定，兩個母體平均數差異檢定 t檢定，兩個母體平均數差異檢定，假設變異數不相等 單因子變異數分析 t檢定，成對母體平均數差異檢定，假設變異數相等', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "90e183535e49", "answer_pdf_sha1": "da9b90c792c6", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 13, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
